	// 事件类型
	// 可选值：
	//
	//	"fault"             - 设备故障（通用）
	//	"transaction_fail"  - 交易失败
	//	"config_change"     - 配置变更（设备本地修改）
	//	"reboot"            - 设备重启（已完成）
	//	"stock_alert"       - 药品库存告警
	//	"custom"            - 自定义事件（具体内容在 detail_json 中）
